index f9155cc66031..cf6b7b87adba 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,62 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(minmax(X+C, Y), minmax(X, Y)) --> select (icmp pred X, Y), C, 0
+  // where minmax is smin/smax/umin/umax and C is a constant (typically 1).
+  // For signed min/max the add must have nsw; for unsigned, nuw.
+  if (auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0)) {
+    if (MinMax0->getIntrinsicID() == MinMax->getIntrinsicID() &&
+        (Op0->hasOneUse() || Op1->hasOneUse())) {
+      Value *A = MinMax0->getLHS(), *B = MinMax0->getRHS();
+      Value *C = MinMax->getLHS(), *D = MinMax->getRHS();
+      Value *X = nullptr, *Y = nullptr;
+      const APInt *ConstVal = nullptr;
+      bool IsAddA = false;
+
+      // Try to match: one operand of MinMax0 is (add X, ConstVal),
+      // the corresponding operand of MinMax is X,
+      // and the other operands are the same Y.
+      auto TryMatch = [&](Value *AddOp, Value *OtherOp0, Value *PlainOp,
+                          Value *OtherOp1, bool AddIsA) -> bool {
+        if (OtherOp0 == OtherOp1 &&
+            match(AddOp, m_Add(m_Value(X), m_APInt(ConstVal))) &&
+            PlainOp == X) {
+          Y = OtherOp0;
+          IsAddA = AddIsA;
+          return true;
+        }
+        X = nullptr;
+        ConstVal = nullptr;
+        return false;
+      };
+
+      if (TryMatch(A, B, C, D, true) || TryMatch(A, B, D, C, true) ||
+          TryMatch(B, A, C, D, false) || TryMatch(B, A, D, C, false)) {
+
+        if (ConstVal && ConstVal->getSExtValue() == 1) {
+          // Check that the add has the appropriate nowrap flag
+          bool IsSigned = MinMax->isSigned();
+          Value *AddVal = IsAddA ? A : B;
+          auto *AddI = dyn_cast<OverflowingBinaryOperator>(AddVal);
+
+          bool HasValidFlag = false;
+          if (AddI && AddI->getOpcode() == Instruction::Add) {
+            if ((IsSigned && AddI->hasNoSignedWrap()) ||
+                (!IsSigned && AddI->hasNoUnsignedWrap()))
+              HasValidFlag = true;
+          }
+
+          if (HasValidFlag) {
+            ICmpInst::Predicate Pred = MinMax->getPredicate();
+            Value *Cmp = Builder.CreateICmp(Pred, X, Y);
+            return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                      ConstantInt::get(Ty, 0));
+          }
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

@@ -2731,6 +2787,24 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     return BinaryOperator::CreateSub(X, Not);
   }

+  // min(X+1, Y) - min(X, Y) --> zext X < Y
+  // Replacing a sub and at least one min with an icmp
+  // and a zext is a potential improvement.
+  if (match(Op0, m_c_SMin(m_NSWAddLike(m_Value(X), m_One()), m_Value(Y))) &&
+      match(Op1, m_c_SMin(m_Specific(X), m_Specific(Y))) &&
+      I.getType()->getScalarSizeInBits() != 1 &&
+      (Op0->hasOneUse() || Op1->hasOneUse())) {
+    Value *Cond = Builder.CreateICmpSLT(X, Y);
+    return new ZExtInst(Cond, I.getType());
+  }
+  if (match(Op0, m_c_UMin(m_NUWAddLike(m_Value(X), m_One()), m_Value(Y))) &&
+      match(Op1, m_c_UMin(m_Specific(X), m_Specific(Y))) &&
+      I.getType()->getScalarSizeInBits() != 1 &&
+      (Op0->hasOneUse() || Op1->hasOneUse())) {
+    Value *Cond = Builder.CreateICmpULT(X, Y);
+    return new ZExtInst(Cond, I.getType());
+  }
+
   // Optimize pointer differences into the same array into a size.  Consider:
   //  &A[10] - &A[0]: we should compile this to "10".
   Value *LHSOp, *RHSOp;

